package com.chaobo.scm.supplier.domain.quality;import com.chaobo.scm.common.error.BusinessException;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import org.junit.jupiter.api.Test;import java.time.*;import java.util.concurrent.atomic.AtomicLong;import static org.assertj.core.api.Assertions.*;
class SupplierQualityIssueAggregateTest{private final Ids ids=new Ids();@Test void shouldCompleteRectification(){var a=SupplierQualityIssueAggregate.create(1,"WMS","QC-1","PERFORMANCE",3,"性能不合格",0,ids);a.requestRectification(OffsetDateTime.now().plusDays(3),1,ids);a.submitPlan("调整工艺并全检",2,ids);a.verify(true,"复检通过",3,ids);assertThat(a.status()).isEqualTo(QualityIssueStatus.CLOSED);assertThat(a.pullEvents()).hasSize(4);}@Test void shouldRejectBlankPlan(){var a=SupplierQualityIssueAggregate.create(1,"WMS","QC-1","PERFORMANCE",3,"性能不合格",0,ids);a.requestRectification(OffsetDateTime.now().plusDays(3),1,ids);assertThatThrownBy(()->a.submitPlan("",2,ids)).isInstanceOf(BusinessException.class);}private static class Ids implements IdentifierGenerator{private final AtomicLong n=new AtomicLong(1);public long nextId(){return n.getAndIncrement();}public String nextBusinessNo(String p){return p+n.getAndIncrement();}}}
